// Error response - handles multiple failure modes
const input = $input.first().json;
const reason = input.errorReason || 'unknown';

let errorMsg;
if (reason === 'no_category') {
  errorMsg = 'I could not detect a category. Please include one of:\n- Area Rug\n- Outdoor Rug\n- Hallway Runner\n- Shag Rug\n\n**Example input:**\nArea Rug\nfocus: washable';
} else if (reason === 'no_products') {
  errorMsg = 'No products were returned for this category. The pre-scraped dataset may not have refreshed yet, or the program API may be temporarily unavailable. Try again in a few minutes, or contact the program team if this persists.';
} else {
  errorMsg = 'An unknown error occurred. Please try again or contact the program team.';
}

return [{ json: { error: true, message: errorMsg, reason } }];

// STAGE 1: Input Parser (v2 - URLs no longer needed)
// Extracts category + optional focus from chat input.

const input = $input.first().json.chatInput || '';

// Define valid categories
const categories = [
  { key: 'area_rug', display: 'Area Rug', patterns: ['area rug', 'area rugs'] },
  { key: 'outdoor_rug', display: 'Outdoor Rug', patterns: ['outdoor rug', 'outdoor rugs', 'patio rug'] },
  { key: 'hallway_runner', display: 'Hallway Runner', patterns: ['hallway runner', 'runner rug', 'hall runner', 'runners'] },
  { key: 'shag_rug', display: 'Shag Rug', patterns: ['shag rug', 'shag rugs', 'shaggy rug'] }
];

let selectedCategory = null;
let categoryKey = null;
const lowerInput = input.toLowerCase();
for (const cat of categories) {
  for (const pattern of cat.patterns) {
    if (lowerInput.includes(pattern)) {
      selectedCategory = cat.display;
      categoryKey = cat.key;
      break;
    }
  }
  if (selectedCategory) break;
}

// Optional focus keyword
const focusMatch = input.match(/focus\s*:\s*([^\n]+)/i);
const focus = focusMatch ? focusMatch[1].trim() : '';

const hasCategory = !!selectedCategory;
const hasValidInput = hasCategory;

return [{
  json: {
    selectedCategory,
    categoryKey,
    focus,
    hasCategory,
    hasValidInput,
    errorReason: hasCategory ? null : 'no_category'
  }
}];

// Reshape FastAPI response to legacy { amazonProducts } shape
// expected by Merge All Data1 and downstream Mistral pipeline.
const r = $input.first().json;
const products = r.products || [];

return [{
  json: {
    amazonProducts: products.map(p => ({
      url: p.url,
      name: p.name,
      price: p.price,
      details: p.details || [],
      pattern: p.pattern || '',
      image_url: p.image_url || '',
      rating: p.rating || '',
      review_count: p.review_count || '',
      scraped_at: r.scraped_at || new Date().toISOString()
    })),
    totalProducts: products.length,
    scrapedAt: r.scraped_at || new Date().toISOString()
  }
}];

// Reshape Apify actor output to { amazonProducts } shape
// expected by Merge All Data1 and downstream Mistral pipeline.
const items = $input.all().map(i => i.json);

return [{
  json: {
