// Get category key for Extern API calls
const categoryKey = $('Input Parser1').first().json.categoryKey;
const selectedCategory = $('Input Parser1').first().json.selectedCategory;

return [{
  json: {
    categoryKey: categoryKey || 'area_rug',
    selectedCategory: selectedCategory || 'Area Rug'
  }
