// Merge all social data from Extern API (with image support)
let instagram = { items: [] };
let pinterest = { items: [] };
let blogs = { items: [] };

try {
  instagram = $('Fetch Instagram').first().json || { items: [] };
} catch (e) { instagram = { items: [] }; }

try {
  pinterest = $('Fetch Pinterest').first().json || { items: [] };
} catch (e) { pinterest = { items: [] }; }

try {
  blogs = $('Fetch Blogs').first().json || { items: [] };
} catch (e) { blogs = { items: [] }; }

// Extract images for analysis (limit to 2-3 per source)
const extractImages = (items, source, limit = 3) => {
  return (items || [])
    .filter(item => item.image_base64)
    .slice(0, limit)
    .map(item => ({
      source: source,
      id: item.id,
      caption: item.caption || '',
      image_base64: item.image_base64,
      mime_type: item.image_mime_type || 'image/jpeg'
    }));
};

const socialImages = [
  ...extractImages(instagram.items, 'instagram', 3),
  ...extractImages(pinterest.items, 'pinterest', 3)
];

return [{
  json: {
    socialData: {
      instagram: instagram.items || [],
      pinterest: pinterest.items || [],
      blogs: blogs.items || []
    },
    socialImages: socialImages,
    totalSocialItems: (instagram.items?.length || 0) + (pinterest.items?.length || 0) + (blogs.items?.length || 0),
    totalSocialImages: socialImages.length,
    externApiStatus: {
      instagram: instagram.items?.length > 0 ? 'success' : 'empty_or_failed',
      pinterest: pinterest.items?.length > 0 ? 'success' : 'empty_or_failed',
      blogs: blogs.items?.length > 0 ? 'success' : 'empty_or_failed'
    }
  }
}];

// Extract captions and hashtags from social data as visual trend signals
  const socialData = $('Merge Social Data1').first().json.socialData;

  const instagram = socialData?.instagram || [];
  const pinterest = socialData?.pinterest || [];

  // Combine all captions and hashtags
  const instagramInsights = instagram.map(post => ({
    source: 'instagram',
    caption: post.caption || '',
    hashtags: post.hashtags || [],
    engagement: post.engagement || 0
  }));

  const pinterestInsights = pinterest.map(pin => ({
    source: 'pinterest',
    caption: pin.caption || '',
    hashtags: pin.hashtags || [],
    engagement: pin.engagement || 0
  }));

  const allInsights = [...instagramInsights, ...pinterestInsights];

  // Extract all hashtags for trend analysis
  const allHashtags = allInsights.flatMap(item => item.hashtags);
  const hashtagCounts = {};
  allHashtags.forEach(tag => {
    hashtagCounts[tag] = (hashtagCounts[tag] || 0) + 1;
  });

  // Sort hashtags by frequency
  const topHashtags = Object.entries(hashtagCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 20)
    .map(([tag, count]) => ({ tag, count }));

  // Combine all captions for trend keywords
  const allCaptions = allInsights.map(item => item.caption).join(' ');

  return [{
    json: {
      imageAnalysis: {
        trend_summary: {
          top_hashtags: topHashtags,
          total_posts_analyzed: allInsights.length,
          instagram_count: instagram.length,
          pinterest_count: pinterest.length,
          caption_insights: allCaptions.substring(0, 2000) // Limit length
        },
        source: 'social_captions_and_hashtags'
      },
      socialImages: allInsights,
      analysisSuccess: true,
      reason: 'Using social captions and hashtags for trend analysis'
    }
  }];

