// Clean prompt for Hugging Face API
let inputPrompt = $input.first().json.output || '';
const segmentName = $input.first().json.segment?.name || 'Style';

// Remove line breaks
let cleanPrompt = inputPrompt.split(/\r?\n/).join(' ');

// Remove Markdown formatting
cleanPrompt = cleanPrompt.replace(/\*\*/g, '').replace(/\*/g, '');

// Replace double quotes with single quotes
cleanPrompt = cleanPrompt.replace(/"/g, "'");

// Remove extra whitespace
cleanPrompt = cleanPrompt.replace(/\s+/g, ' ').trim();

// Add quality boosters if not present
if (!cleanPrompt.toLowerCase().includes('professional')) {
  cleanPrompt = 'Professional interior design photography, ' + cleanPrompt;
}
if (!cleanPrompt.toLowerCase().includes('high quality')) {
  cleanPrompt += ', high quality, detailed textures, natural lighting';
}

return [{
  json: {
    prompt: cleanPrompt,
    segmentName: segmentName
  }
}];

// Encode image to base64 for HTML embedding
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const segmentName = item.json.segmentName || 'Style';

  // Check if we have binary data
  if (item.binary && item.binary.data) {
    try {
      // Use n8n helper to get actual binary buffer (not the filesystem pointer)
      const binaryBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
      const base64String = binaryBuffer.toString('base64');

      results.push({
        json: {
          segmentName: segmentName,
          base64Image: base64String,
          mimeType: item.binary.data.mimeType || 'image/png',
          hasImage: true
        }
      });
    } catch (error) {
      results.push({
        json: {
          segmentName: segmentName,
          base64Image: null,
          mimeType: null,
          hasImage: false,
          error: 'Failed to encode: ' + error.message
        }
      });
    }
  } else {
    results.push({
      json: {
        segmentName: segmentName,
        base64Image: null,
        mimeType: null,
        hasImage: false,
        error: 'No binary data returned'
      }
    });
  }
}

return results;

// Collect all generated images
const allImages = $input.all().map(item => ({
  segmentName: item.json.segmentName,
  base64Image: item.json.base64Image,
  mimeType: item.json.mimeType || 'image/png',
  hasImage: item.json.hasImage || false
}));

const validImages = allImages.filter(img => img.hasImage && img.base64Image);

return [{
  json: {
    generatedImages: validImages,
    totalImages: validImages.length,
    failedImages: allImages.length - validImages.length
  }
}];

