// Inject generated images (replaces {{GENERATED_IMAGE_N}} placeholders)
var genImages = imageStore.generatedImages || [];
for (var i = 0; i < genImages.length; i++) {
  var img = genImages[i];
  var placeholder = '{{GENERATED_IMAGE_' + i + '}}';
  var base64 = img.base64 || img.base64Image || '';
  if (base64) {
    var dataUrl = 'data:image/png;base64,' + base64;
    html = html.split(placeholder).join(dataUrl);
  }
}

// Inject social images (replaces {{SOCIAL_IMAGE_N}} placeholders)
var socialImages = imageStore.socialRefImages || [];
for (var j = 0; j < socialImages.length; j++) {
  var simg = socialImages[j];
  var splaceholder = '{{SOCIAL_IMAGE_' + j + '}}';
  var smimeType = simg.mime_type || simg.mimeType || 'image/jpeg';
  var sbase64 = simg.image_base64 || simg.base64 || '';
  if (sbase64) {
    var sdataUrl = 'data:' + smimeType + ';base64,' + sbase64;
    html = html.split(splaceholder).join(sdataUrl);
