}


// Catch AI's invented filenames like moodboard_1.png / social_1.jpg and substitute real images
  html = html.replace(/<img([^>]*?)\ssrc=["']moodboard[_-]?(\d+)\.[a-z]+["']([^>]*)>/gi, function(_, pre, n, post) {
    var idx = parseInt(n) - 1;
    var img = genImages[idx];
    var b64 = img && (img.base64 || img.base64Image);
    return b64 ? '<img' + pre + ' src="data:image/png;base64,' + b64 + '"' + post + '>' : '';
  });

  html = html.replace(/<img([^>]*?)\ssrc=["']social[_-]?(\d+)\.[a-z]+["']([^>]*)>/gi, function(_, pre, n, post) {
    var idx = parseInt(n) - 1;
    var simg = socialImages[idx];
