    var mt = (simg && (simg.mime_type || simg.mimeType)) || 'image/jpeg';
    return b64 ? '<img' + pre + ' src="data:' + mt + ';base64,' + b64 + '"' + post + '>' : '';
  });


// Clean up any unreplaced placeholders so they don't appear as raw text
html = html.replace(/\{\{GENERATED_IMAGE_\d+\}\}/g, '');
html = html.replace(/\{\{SOCIAL_IMAGE_\d+\}\}/g, '');

return [{ json: { cleanedHtml: html } }];

// Validate report sections and check images were injected
const html = $input.first().json.cleanedHtml || '';

const requiredSections = [
  { name: 'Executive Summary', pattern: /executive\s*summary/i },
  { name: 'Scope', pattern: /scope|research/i },
  { name: 'Category', pattern: /category/i },
  { name: 'Attribute', pattern: /attribute|material|size/i },
  { name: 'Risk', pattern: /risk/i },
  { name: 'Demand', pattern: /demand|signal|seo/i }
];

const validation = {
  isValid: true,
  sectionsFound: [],
  sectionsMissing: [],
  warnings: []
};

requiredSections.forEach(section => {
  if (section.pattern.test(html)) {
    validation.sectionsFound.push(section.name);
  } else {
    validation.sectionsMissing.push(section.name);
  }
});

// Check for injected images (both PNG and JPEG)
const pngImages = (html.match(/data:image\/png;base64,/g) || []).length;
const jpegImages = (html.match(/data:image\/jpeg;base64,/g) || []).length;
validation.imageCount = pngImages + jpegImages;

if (validation.imageCount === 0) {
  validation.warnings.push('No images embedded');
}

// Check HTML structure
if (!html.includes('</html>')) {
  validation.warnings.push('HTML may be truncated');
  validation.isValid = false;
}

return [{ json: { cleanedHtml: html, validation } }];

